1	/**
2	 * Inline holo-card reveal shown above the chat stream. Four-state machine:
3	 *   idle (giftbox) → vibrating (anticipation) → bursting (scale-up + fade)
4	 *   → revealed (editable card with confetti)
5	 *
6	 * On hover the giftbox scales and lifts slightly, signalling it's interactive.
7	 * The "bursting" step double-buffers the visuals: the giftbox scales and fades
8	 * out while the card scales in underneath, so the transition reads as the box
9	 * opening rather than disappearing flatly.
10	 */
11	
12	"use client";
13	
14	import confetti from "canvas-confetti";
15	import { AnimatePresence } from "motion/react";
16	import * as m from "motion/react-m";
17	import Image from "next/image";
18	import { useEffect, useRef, useState } from "react";
19	
20	import { HoloCardEditor } from "@/components/ui/holo-card/HoloCardEditor";
21	import type { HoloCardDisplayData } from "@/components/ui/holo-card/types";
22	import { HOLO_CARD_HEIGHT, HOLO_CARD_WIDTH } from "../../constants";
23	import type { PersonalizationData } from "../../types/websocket";
24	
25	interface HoloCardRevealProps {
26	  personalizationData: PersonalizationData;
27	}
28	
29	type RevealState = "idle" | "vibrating" | "bursting" | "revealed";
30	
31	// Container is sized to the holo card so the giftbox and the revealed card
32	// share an anchor — no layout jump when the state flips.
33	const GIFTBOX_SRC = "/images/onboarding/giftbox.png";
34	
35	export function HoloCardReveal({ personalizationData }: HoloCardRevealProps) {
36	  const [revealState, setRevealState] = useState<RevealState>("idle");
37	  const cardWrapRef = useRef<HTMLDivElement>(null);
38	
39	  // Choreography on reveal:
40	  //   t=0    card mounts, springs in from scale 0.6
41	  //   t=40   smooth scroll kicks off so the card is in view as it grows
42	  //   t=520  scroll has settled — fire confetti from the card's actual
43	  //          on-screen centre so the burst lands ON the card, not on the
44	  //          original (pre-scroll) viewport position
45	  // Times are deliberately offset; firing confetti before the scroll settles
46	  // makes the particles spawn at a stale origin and look detached.
47	  useEffect(() => {
48	    if (revealState !== "revealed") return;
49	    const scrollTimer = window.setTimeout(() => {
50	      cardWrapRef.current?.scrollIntoView({
51	        behavior: "smooth",
52	        block: "center",
53	      });
54	    }, 40);
55	    const confettiTimer = window.setTimeout(() => {
56	      const node = cardWrapRef.current;
57	      const origin = node
58	        ? (() => {
59	            const rect = node.getBoundingClientRect();
60	            return {
61	              x: (rect.left + rect.width / 2) / window.innerWidth,
62	              y: (rect.top + rect.height / 2) / window.innerHeight,
63	            };
64	          })()
65	        : { x: 0.5, y: 0.55 };
66	      confetti({
67	        particleCount: 160,
68	        spread: 80,
69	        startVelocity: 45,
70	        origin,
71	      });
72	    }, 520);
73	    return () => {
74	      window.clearTimeout(scrollTimer);
75	      window.clearTimeout(confettiTimer);
76	    };
77	  }, [revealState]);
78	
79	  const holoCardData: HoloCardDisplayData = {
80	    house: personalizationData.house ?? "bluehaven",
81	    name: personalizationData.name ?? "User",
82	    personality_phrase:
83	      personalizationData.personality_phrase ?? "Curious Adventurer",
84	    user_bio:
85	      personalizationData.user_bio ??
86	      "A passionate individual exploring new possibilities and making an impact.",
87	    account_number: personalizationData.account_number
88	      ? `#${personalizationData.account_number}`
89	      : "#00000",
90	    member_since:
91	      personalizationData.member_since ??
92	      new Date().toLocaleDateString("en-US", {
93	        month: "short",
94	        day: "numeric",
95	        year: "numeric",
96	      }),
97	    overlay_color: personalizationData.overlay_color ?? "rgba(0,0,0,0)",
98	    overlay_opacity: personalizationData.overlay_opacity ?? 40,
99	    holo_card_id: personalizationData.holo_card_id,
100	  };
101	
102	  const handleGiftboxClick = () => {
103	    if (revealState !== "idle") return;
104	    setRevealState("vibrating");
105	  };
106	
107	  const handleVibrationComplete = () => {
108	    setRevealState("bursting");
109	  };
110	
111	  const handleBurstComplete = () => {
112	    setRevealState("revealed");
113	  };
114	
115	  return (
116	    <m.div
117	      className="flex flex-col items-center py-2"
118	      initial={{ opacity: 0, y: 8 }}
119	      animate={{ opacity: 1, y: 0 }}
120	      transition={{ duration: 0.35 }}
121	    >
122	      <div
123	        className="relative flex items-center justify-center"
