127	        }}
128	      >
129	        <AnimatePresence mode="wait">
130	          {revealState !== "revealed" && (
131	            <m.button
132	              key="giftbox"
133	              type="button"
134	              aria-label="Tap to reveal your personalized GAIA card"
135	              onClick={handleGiftboxClick}
136	              disabled={revealState !== "idle"}
137	              className="group relative flex cursor-pointer items-center justify-center bg-transparent outline-none"
138	              style={{ perspective: 1000 }}
139	              initial={{ opacity: 0, scale: 0.9 }}
