142	                  ? {
143	                      opacity: 1,
144	                      scale: [1, 1.04, 1.04, 1, 1, 1, 1, 1],
145	                      rotate: [0, -8, 8, -10, 10, -6, 6, -3, 3, 0],
146	                      x: [0, -4, 4, -6, 6, -4, 4, -2, 2, 0],
147	                    }
148	                  : revealState === "bursting"
149	                    ? {
150	                        opacity: [1, 1, 0],
151	                        scale: [1, 1.3, 1.6],
152	                        rotate: 0,
153	                        x: 0,
154	                      }
155	                    : { opacity: 1, scale: 1, rotate: 0, x: 0 }
156	              }
157	              whileHover={
158	                revealState === "idle" ? { scale: 1.06, y: -6 } : undefined
159	              }
160	              whileTap={revealState === "idle" ? { scale: 0.97 } : undefined}
161	              transition={
162	                revealState === "vibrating"
163	                  ? { duration: 0.7, ease: "easeInOut" }
164	                  : revealState === "bursting"
165	                    ? { duration: 0.45, ease: "easeOut" }
166	                    : { type: "spring", stiffness: 320, damping: 22 }
167	              }
168	              onAnimationComplete={
169	                revealState === "vibrating"
170	                  ? handleVibrationComplete
171	                  : revealState === "bursting"
172	                    ? handleBurstComplete
173	                    : undefined
174	              }
175	            >
176	              <m.div
177	                className="relative flex flex-col items-center"
178	                style={{ width: HOLO_CARD_WIDTH }}
