183	                    : undefined
184	                }
185	              >
186	                <Image
187	                  src={GIFTBOX_SRC}
188	                  alt=""
189	                  width={1360}
190	                  height={952}
191	                  priority
192	                  className="h-auto w-[240px] select-none"
193	                  draggable={false}
194	                />
195	                {revealState === "idle" && (
196	                  <m.p
197	                    className="mt-4 text-sm text-white/80"
198	                    initial={{ opacity: 0 }}
199	                    animate={{ opacity: [0.5, 1, 0.5] }}
200	                    transition={{ duration: 2.4, repeat: Infinity }}
201	                  >
202	                    Click to open
203	                  </m.p>
204	                )}
205	              </m.div>
206	            </m.button>
207	          )}
208	
209	          {revealState === "revealed" && (
210	            <m.div
211	              key="card"
212	              ref={cardWrapRef}
213	              className="flex flex-col items-center gap-4"
