1	/**
2	 * Drives the live backend connection during onboarding: fetches the initial
3	 * personalization snapshot via REST, opens a WebSocket for stage events, and
4	 * falls back to REST polling if the socket goes silent.
5	 */
6	
7	"use client";
8	
9	import { type Dispatch, useEffect, useRef } from "react";
10	
11	import { getPersonalization } from "../api/onboardingApi";
12	import type { Action, OnboardingState, Stage } from "../state/types";
13	import type {
14	  OnboardingStage,
15	  PersonalizationData,
16	  StagePayloads,
17	} from "../types/websocket";
18	
19	const MAX_RECONNECT_ATTEMPTS = 10;
20	const RECONNECT_BASE_DELAY_MS = 1000;
21	// If the WS connects but stays silent past this window, kick off a REST
22	// poll so the user isn't stuck behind a silent socket.
23	const WS_SILENCE_FALLBACK_MS = 5000;
24	// Once polling, refetch the snapshot at this cadence. Cleared the moment
25	// any WS event lands.
26	const POLL_INTERVAL_MS = 3000;
27	
28	function getWsUrl(): string {
29	  const base =
30	    process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:8000/api/v1/";
31	  return (
32	    base.replace("http://", "ws://").replace("https://", "wss://") +
33	    "ws/connect"
34	  );
35	}
36	
37	/**
38	 * Discriminated-union envelope: narrowing on `stage` automatically narrows
39	 * `payload`, so handlers can be typed without per-case `as` casts.
40	 */
41	type StageEnvelope = {
42	  [K in OnboardingStage]: { stage: K; payload: StagePayloads[K] };
43	}[OnboardingStage];
